import random
import math
import heapq
import collections
import itertools

def compute_model_placement(gpu_num, models):
    GPU_MEM_SIZE = 80

    def calculate_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        sum_req_rate_slo = sum(m.req_rate / m.slo for m in gpu_models)
        sum_model_size = sum(m.model_size for m in gpu_models)
        if sum_model_size > GPU_MEM_SIZE:
            return float('inf')
        remaining_mem = GPU_MEM_SIZE - sum_model_size
        if remaining_mem <= 0:
            return float('inf') if sum_req_rate_slo > 0 else 0.0
        return sum_req_rate_slo / remaining_mem

    def calculate_max_kvpr(placement):
        max_kvpr_val = 0.0
        for gpu_id in range(gpu_num):
            max_kvpr_val = max(max_kvpr_val, calculate_kvpr(placement[gpu_id]))
        return max_kvpr_val

    def get_gpu_memory_usage(placement):
        return [sum(m.model_size for m in placement[gpu_id]) for gpu_id in range(gpu_num)]

    def create_initial_solution_greedy():
        placement = {i: [] for i in range(gpu_num)}
        gpu_mem_usage = [0] * gpu_num

        # Sort models by KVPR density (req_rate/slo) / model_size
        sorted_models = sorted(models, key=lambda m: (m.req_rate / m.slo) / (m.model_size + 1e-9), reverse=True)

        for model in sorted_models:
            best_gpu = -1
            min_current_kvpr = float('inf')

            # Find GPU that results in the minimum KVPR after placement
            for gpu_id in range(gpu_num):
                if gpu_mem_usage[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    # Temporarily add model to calculate potential KVPR
                    placement[gpu_id].append(model)
                    potential_kvpr = calculate_kvpr(placement[gpu_id])
                    placement[gpu_id].pop() # Remove temporary addition

                    if potential_kvpr < min_current_kvpr:
                        min_current_kvpr = potential_kvpr
                        best_gpu = gpu_id

            if best_gpu == -1:
                # If no GPU can fit, try to place on the least utilized GPU
                # This scenario should ideally be avoided by problem constraints or a better heuristic
                # For robustness, we'll place it on the one with most remaining space
                best_gpu = max(range(gpu_num), key=lambda g: GPU_MEM_SIZE - gpu_mem_usage[g])
                if gpu_mem_usage[best_gpu] + model.model_size > GPU_MEM_SIZE:
                    # This implies the model itself is too large for any GPU, which should not happen per constraints
                    # Or all GPUs are full and this model cannot fit.
                    # For this problem, we assume it's always possible to place all models.
                    pass 

            placement[best_gpu].append(model)
            gpu_mem_usage[best_gpu] += model.model_size

        return placement

    def get_neighbors(placement):
        neighbors = []
        current_mem_usage = get_gpu_memory_usage(placement)

        # 1. Move a model from one GPU to another
        for src_gpu in range(gpu_num):
            for i, model in enumerate(placement[src_gpu]):
                for dst_gpu in range(gpu_num):
                    if src_gpu == dst_gpu:
                        continue

                    if current_mem_usage[src_gpu] - model.model_size + model.model_size <= GPU_MEM_SIZE and \
                       current_mem_usage[dst_gpu] + model.model_size <= GPU_MEM_SIZE:

                        new_placement = {gpu_id: list(placement[gpu_id]) for gpu_id in range(gpu_num)}
                        moved_model = new_placement[src_gpu].pop(i)
                        new_placement[dst_gpu].append(moved_model)
                        neighbors.append(new_placement)

        # 2. Swap two models between different GPUs
        for gpu1 in range(gpu_num):
            for gpu2 in range(gpu1 + 1, gpu_num):
                for i, model1 in enumerate(placement[gpu1]):
                    for j, model2 in enumerate(placement[gpu2]):

                        mem1_after_swap = current_mem_usage[gpu1] - model1.model_size + model2.model_size
                        mem2_after_swap = current_mem_usage[gpu2] - model2.model_size + model1.model_size

                        if mem1_after_swap <= GPU_MEM_SIZE and mem2_after_swap <= GPU_MEM_SIZE:
                            new_placement = {gpu_id: list(placement[gpu_id]) for gpu_id in range(gpu_num)}
                            new_placement[gpu1][i], new_placement[gpu2][j] = new_placement[gpu2][j], new_placement[gpu1][i]
                            neighbors.append(new_placement)

        return neighbors

    # Use a local search (e.g., Hill Climbing) to refine the solution
    def local_search(initial_placement):
        current_placement = {gpu_id: list(initial_placement[gpu_id]) for gpu_id in range(gpu_num)}
        current_max_kvpr = calculate_max_kvpr(current_placement)

        improved = True
        while improved:
            improved = False
            best_neighbor_placement = None
            best_neighbor_max_kvpr = current_max_kvpr

            # Generate neighbors and find the best one
            for neighbor_placement in get_neighbors(current_placement):
                neighbor_max_kvpr = calculate_max_kvpr(neighbor_placement)
                if neighbor_max_kvpr < best_neighbor_max_kvpr:
                    best_neighbor_max_kvpr = neighbor_max_kvpr
                    best_neighbor_placement = neighbor_placement

            if best_neighbor_placement is not None:
                current_placement = best_neighbor_placement
                current_max_kvpr = best_neighbor_max_kvpr
                improved = True

        return current_placement

    # Generate multiple initial solutions and pick the best one after local search
    best_overall_placement = None
    min_overall_max_kvpr = float('inf')

    # Try a few different initial greedy strategies or random starts
    num_runs = min(10, gpu_num * 2) # Number of restarts

    for _ in range(num_runs):
        # Randomly shuffle models for a different greedy start
        shuffled_models = list(models)
        random.shuffle(shuffled_models)

        # Create initial placement using a greedy approach with shuffled models
        initial_placement_attempt = {i: [] for i in range(gpu_num)}
        gpu_mem_usage = [0] * gpu_num

        for model in shuffled_models:
            best_gpu = -1
            min_potential_kvpr = float('inf')

            for gpu_id in range(gpu_num):
                if gpu_mem_usage[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    initial_placement_attempt[gpu_id].append(model)
                    potential_kvpr = calculate_kvpr(initial_placement_attempt[gpu_id])
                    initial_placement_attempt[gpu_id].pop()

                    if potential_kvpr < min_potential_kvpr:
                        min_potential_kvpr = potential_kvpr
                        best_gpu = gpu_id

            if best_gpu == -1: # Fallback if no perfect fit, find one that fits
                for gpu_id in range(gpu_num):
                    if gpu_mem_usage[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                        best_gpu = gpu_id
                        break

            if best_gpu != -1:
                initial_placement_attempt[best_gpu].append(model)
                gpu_mem_usage[best_gpu] += model.model_size
            else:
                # Should not happen if models fit within GPU_MEM_SIZE
                pass

        # Apply local search to the generated initial placement
        refined_placement = local_search(initial_placement_attempt)
        current_max_kvpr = calculate_max_kvpr(refined_placement)

        if current_max_kvpr < min_overall_max_kvpr:
            min_overall_max_kvpr = current_max_kvpr
            best_overall_placement = refined_placement

    # If no valid placement was found (highly unlikely given problem constraints)
    if best_overall_placement is None:
        best_overall_placement = {i: [] for i in range(gpu_num)}
        for i, model in enumerate(models):
            best_overall_placement[i % gpu_num].append(model)

    return best_overall_placement

