def compute_model_placement(gpu_num, models):
    GPU_MEM_SIZE = 80

    def kvpr_for_gpu(gpu_models):
        if not gpu_models:
            return 0.0
        total_size = sum(m.model_size for m in gpu_models)
        if total_size > GPU_MEM_SIZE:
            return float('inf')
        remaining = GPU_MEM_SIZE - total_size
        if remaining <= 0:
            return 0.0 if sum(m.req_rate / m.slo for m in gpu_models) == 0 else float('inf')
        return sum(m.req_rate / m.slo for m in gpu_models) / remaining

    def max_kvpr(placement):
        return max(kvpr_for_gpu(placement[gpu]) for gpu in range(gpu_num))

    # Initial solution using greedy bin packing with KVPR awareness
    def create_initial():
        placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        gpu_usage = [0] * gpu_num

        # Sort models by (req_rate/slo) / model_size (KVPR density) descending
        sorted_models = sorted(models, 
            key=lambda m: (m.req_rate / m.slo) / m.model_size if m.model_size > 0 else 0, 
            reverse=True)

        for model in sorted_models:
            best_gpu = -1
            best_increase = float('inf')

            for gpu in range(gpu_num):
                if gpu_usage[gpu] + model.model_size <= GPU_MEM_SIZE:
                    # Calculate KVPR increase if placed here
                    old_kvpr = kvpr_for_gpu(placement[gpu])
                    placement[gpu].append(model)
                    new_kvpr = kvpr_for_gpu(placement[gpu])
                    placement[gpu].pop()

                    kvpr_increase = new_kvpr - old_kvpr
                    if kvpr_increase < best_increase:
                        best_increase = kvpr_increase
                        best_gpu = gpu

            if best_gpu >= 0:
                placement[best_gpu].append(model)
                gpu_usage[best_gpu] += model.model_size
            else:
                # If no GPU can fit, place on GPU with most space
                best_gpu = max(range(gpu_num), key=lambda g: GPU_MEM_SIZE - gpu_usage[g])
                placement[best_gpu].append(model)
                gpu_usage[best_gpu] += model.model_size

        return placement

    # Tabu Search with adaptive neighborhood
    current = create_initial()
    best = {gpu: list(current[gpu]) for gpu in range(gpu_num)}
    best_value = max_kvpr(current)

    tabu_list = collections.deque(maxlen=20)
    iterations_without_improvement = 0

    for iteration in range(500):
        # Generate candidate moves
        candidates = []

        # Move a model from one GPU to another
        for src_gpu in range(gpu_num):
            for model in current[src_gpu]:
                for dst_gpu in range(gpu_num):
                    if src_gpu == dst_gpu:
                        continue

                    # Check memory constraint
                    src_size = sum(m.model_size for m in current[src_gpu]) - model.model_size
                    dst_size = sum(m.model_size for m in current[dst_gpu]) + model.model_size

                    if dst_size <= GPU_MEM_SIZE:
                        move = ('move', src_gpu, dst_gpu, model)
                        if move not in tabu_list:
                            # Create new placement for evaluation
                            new_placement = {gpu: list(current[gpu]) for gpu in range(gpu_num)}
                            new_placement[src_gpu].remove(model)
                            new_placement[dst_gpu].append(model)
                            new_value = max_kvpr(new_placement)
                            candidates.append((new_value, move, new_placement))

        # Swap two models between different GPUs
        for gpu1 in range(gpu_num):
            for gpu2 in range(gpu1 + 1, gpu_num):
                for model1 in current[gpu1]:
                    for model2 in current[gpu2]:
                        # Check memory constraints
                        gpu1_new_size = sum(m.model_size for m in current[gpu1]) - model1.model_size + model2.model_size
                        gpu2_new_size = sum(m.model_size for m in current[gpu2]) - model2.model_size + model1.model_size

                        if gpu1_new_size <= GPU_MEM_SIZE and gpu2_new_size <= GPU_MEM_SIZE:
                            move = ('swap', gpu1, gpu2, model1, model2)
                            if move not in tabu_list:
                                new_placement = {gpu: list(current[gpu]) for gpu in range(gpu_num)}
                                new_placement[gpu1].remove(model1)
                                new_placement[gpu1].append(model2)
                                new_placement[gpu2].remove(model2)
                                new_placement[gpu2].append(model1)
                                new_value = max_kvpr(new_placement)
                                candidates.append((new_value, move, new_placement))

        if not candidates:
            break

        # Select best candidate
        candidates.sort(key=lambda x: x[0])
        best_candidate_value, best_move, best_candidate_placement = candidates[0]

        # Aspiration criterion: accept if better than global best
        if best_candidate_value < best_value:
            best_value = best_candidate_value
            best = best_candidate_placement
            current = best_candidate_placement
            tabu_list.append(best_move)
            iterations_without_improvement = 0
        else:
            # Accept if better than current or with probability
            if best_candidate_value <= max_kvpr(current) or random.random() < math.exp(-5 * iteration / 500):
                current = best_candidate_placement
                tabu_list.append(best_move)

            iterations_without_improvement += 1
            if iterations_without_improvement > 50:
                # Diversification: randomly perturb the solution
                for _ in range(5):
                    src_gpu = random.randint(0, gpu_num - 1)
                    if current[src_gpu]:
                        model = random.choice(current[src_gpu])
                        dst_gpu = random.randint(0, gpu_num - 1)
                        if src_gpu != dst_gpu:
                            dst_size = sum(m.model_size for m in current[dst_gpu]) + model.model_size
                            if dst_size <= GPU_MEM_SIZE:
                                current[src_gpu].remove(model)
                                current[dst_gpu].append(model)
                                break
                iterations_without_improvement = 0

    # Final local improvement pass
    improved = True
    while improved:
        improved = False
        for src_gpu in range(gpu_num):
            for model in best[src_gpu]:
                for dst_gpu in range(gpu_num):
                    if src_gpu == dst_gpu:
                        continue

                    src_size = sum(m.model_size for m in best[src_gpu]) - model.model_size
                    dst_size = sum(m.model_size for m in best[dst_gpu]) + model.model_size

                    if dst_size <= GPU_MEM_SIZE:
                        # Try the move
                        best[src_gpu].remove(model)
                        best[dst_gpu].append(model)
                        new_value = max_kvpr(best)

                        if new_value < best_value:
                            best_value = new_value
                            improved = True
                        else:
                            # Revert
                            best[dst_gpu].remove(model)
                            best[src_gpu].append(model)

    return best

