        remaining_mem = GPU_MEM_SIZE - sum_model_size
        if remaining_mem <= 0:
            return float('inf') if sum_req_rate_slo > 0 else 0.0
        return sum_req_rate_slo / remaining_mem

    def calculate_max_kvpr(placement):
        max_kvpr = 0.0
        for gpu_id in range(gpu_num):
            max_kvpr = max(max_kvpr, calculate_kvpr(placement[gpu_id]))
        return max_kvpr

    def create_initial_solution():
        placement = {i: [] for i in range(gpu_num)}
        gpu_mem_usage = [0] * gpu_num

        sorted_models = sorted(models, key=lambda m: (m.req_rate / m.slo) / (m.model_size + 1e-9), reverse=True)

        for model in sorted_models:
            best_gpu = -1
            best_increase = float('inf')

            for gpu_id in range(gpu_num):
                if gpu_mem_usage[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    placement[gpu_id].append(model)
                    kvpr_after = calculate_kvpr(placement[gpu_id])
                    placement[gpu_id].pop()

                    if kvpr_after < best_increase:
                        best_increase = kvpr_after
                        best_gpu = gpu_id

            if best_gpu == -1:
                return None

            placement[best_gpu].append(model)
            gpu_mem_usage[best_gpu] += model.model_size

        return placement

    def get_neighbor(placement):
        new_placement = {gpu_id: list(placement[gpu_id]) for gpu_id in range(gpu_num)}

        if random.random() < 0.8:
            src_gpu = random.choice(range(gpu_num))
            if not new_placement[src_gpu]:
                return new_placement

            model_idx = random.randrange(len(new_placement[src_gpu]))
            model = new_placement[src_gpu].pop(model_idx)

            dest_gpu = random.choice(range(gpu_num))
            new_placement[dest_gpu].append(model)
        else:
            if gpu_num < 2:
                return new_placement

            gpu1, gpu2 = random.sample(range(gpu_num), 2)
            if not new_placement[gpu1] or not new_placement[gpu2]:
                return new_placement

            idx1 = random.randrange(len(new_placement[gpu1]))
            idx2 = random.randrange(len(new_placement[gpu2]))

            model1 = new_placement[gpu1][idx1]
            model2 = new_placement[gpu2][idx2]

            if (sum(m.model_size for m in new_placement[gpu1]) - model1.model_size + model2.model_size <= GPU_MEM_SIZE and
                sum(m.model_size for m in new_placement[gpu2]) - model2.model_size + model1.model_size <= GPU_MEM_SIZE):
                new_placement[gpu1][idx1] = model2
                new_placement[gpu2][idx2] = model1

        return new_placement

    def simulated_annealing(initial_temp=100.0, cooling_rate=0.95, iterations=1000):
        current = create_initial_solution()
        if current is None:
            current = {i: [] for i in range(gpu_num)}
            for i, model in enumerate(models):
                current[i % gpu_num].append(model)

        current_cost = calculate_max_kvpr(current)
        best = {k: list(v) for k, v in current.items()}
        best_cost = current_cost

        temp = initial_temp

        for _ in range(iterations):
            neighbor = get_neighbor(current)
            neighbor_cost = calculate_max_kvpr(neighbor)

            if neighbor_cost < current_cost or random.random() < math.exp((current_cost - neighbor_cost) / temp):
                current = neighbor
                current_cost = neighbor_cost

                if current_cost < best_cost:
                    best = {k: list(v) for k, v in current.items()}
                    best_cost = current_cost

            temp *= cooling_rate

            if best_cost == 0:
                break

        return best

    def local_search_improvement(placement):
        improved = True
        while improved:
            improved = False
            current_cost = calculate_max_kvpr(placement)

            for gpu_from in range(gpu_num):
                for model_idx, model in enumerate(placement[gpu_from]):
                    for gpu_to in range(gpu_num):
                        if gpu_from == gpu_to:
                            continue

                        if (sum(m.model_size for m in placement[gpu_to]) + model.model_size <= GPU_MEM_SIZE):
                            placement[gpu_from].pop(model_idx)
                            placement[gpu_to].append(model)

                            new_cost = calculate_max_kvpr(placement)
                            if new_cost < current_cost:
                                improved = True
                                current_cost = new_cost
                                break
                            else:
                                placement[gpu_to].remove(model)
                                placement[gpu_from].insert(model_idx, model)
                    if improved:
                        break
                if improved:
                    break

        return placement

    best_solution = None
    best_cost = float('inf')

    for _ in range(5):
        sa_solution = simulated_annealing()
        improved_solution = local_search_improvement(sa_solution)
        current_cost = calculate_max_kvpr(improved_solution)

        if current_cost < best_cost:
            best_cost = current_cost
            best_solution = improved_solution

    if best_cost == float('inf'):
        best_solution = {i: [] for i in range(gpu_num)}
        for i, model in enumerate(models):
            best_solution[i % gpu_num].append(model)

    return best_solution

