def compute_model_placement(gpu_num, models):
    GPU_MEM_SIZE = 80

    def calculate_gpu_kvpr(models_on_gpu):
        if not models_on_gpu:
            return 0.0
        sum_req_rate_slo = sum(m.req_rate / m.slo for m in models_on_gpu)
        sum_model_size = sum(m.model_size for m in models_on_gpu)
        if sum_model_size > GPU_MEM_SIZE:
            return float('inf')
        remaining_mem = GPU_MEM_SIZE - sum_model_size
        if remaining_mem <= 0:
            return float('inf') if sum_req_rate_slo > 0 else 0.0
        return sum_req_rate_slo / remaining_mem

    def calculate_max_kvpr(placement):
        max_kvpr = 0.0
        for gpu_id in range(gpu_num):
            max_kvpr = max(max_kvpr, calculate_gpu_kvpr(placement[gpu_id]))
        return max_kvpr

    # Greedy initial placement with randomization
    def create_initial_solution():
        placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        mem_usage = [0] * gpu_num

        # Sort models by model_size descending to place larger models first
        sorted_models = sorted(models, key=lambda m: m.model_size, reverse=True)

        for model in sorted_models:
            # Try to place on GPU with least current memory usage that can fit the model
            best_gpu = None
            min_mem = float('inf')

            # Check available GPUs for the model
            for gpu_id in range(gpu_num):
                if mem_usage[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    if mem_usage[gpu_id] < min_mem:
                        min_mem = mem_usage[gpu_id]
                        best_gpu = gpu_id

            # Place on best available GPU
            if best_gpu is not None:
                placement[best_gpu].append(model)
                mem_usage[best_gpu] += model.model_size
            else:
                # If no GPU can fit this model, assign to the one with most remaining space
                # This is a fallback, not ideal but ensures completeness
                best_gpu = min(range(gpu_num), key=lambda g: mem_usage[g])
                placement[best_gpu].append(model)
                mem_usage[best_gpu] += model.model_size

        return placement

    # Local search improvement using simulated annealing
    def improve_solution(current_placement):
        current_kvpr = calculate_max_kvpr(current_placement)
        best_placement = {k: list(v) for k, v in current_placement.items()}
        best_kvpr = current_kvpr
        temperature = 1000.0
        min_temperature = 1e-8
        cooling_rate = 0.995

        while temperature > min_temperature:
            # Create a neighbor solution
            new_placement = {k: list(v) for k, v in current_placement.items()}

            # Select a random model to move
            models_list = []
            for gpu_id, model_list in new_placement.items():
                for model in model_list:
                    models_list.append((gpu_id, model))

            if not models_list:
                break

            source_gpu_id, model_to_move = random.choice(models_list)

            # Remove model from source
            new_placement[source_gpu_id].remove(model_to_move)

            # Choose destination GPU randomly among those that can fit the model
            possible_dest_gpus = []
            for gpu_id in range(gpu_num):
                if sum(m.model_size for m in new_placement[gpu_id]) + model_to_move.model_size <= GPU_MEM_SIZE:
                    possible_dest_gpus.append(gpu_id)

            if possible_dest_gpus:
                dest_gpu_id = random.choice(possible_dest_gpus)
                new_placement[dest_gpu_id].append(model_to_move)
            else:
                # If no valid GPU, keep it in source
                new_placement[source_gpu_id].append(model_to_move)

            new_kvpr = calculate_max_kvpr(new_placement)

            # Accept or reject the new solution based on simulated annealing
            if new_kvpr < current_kvpr or random.random() < math.exp((current_kvpr - new_kvpr) / temperature):
                current_placement = new_placement
                current_kvpr = new_kvpr

                if new_kvpr < best_kvpr:
                    best_placement = {k: list(v) for k, v in new_placement.items()}
                    best_kvpr = new_kvpr

            temperature *= cooling_rate

        return best_placement

    # Main optimization loop
    best_placement = None
    best_kvpr = float('inf')

    # Run multiple random restarts with local search
    for _ in range(20):
        initial_placement = create_initial_solution()
        improved_placement = improve_solution(initial_placement)
        improved_kvpr = calculate_max_kvpr(improved_placement)

        if improved_kvpr < best_kvpr:
            best_kvpr = improved_kvpr
            best_placement = improved_placement

        if best_kvpr == 0:
            break

    # Fallback to round-robin if no good solution found
    if best_placement is None or best_kvpr == float('inf'):
        final_placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        for i, model in enumerate(models):
            final_placement[i % gpu_num].append(model)
        return final_placement

    return best_placement

