    NUM_ANTS = 30
    MAX_ITER = 200
    EVAP_RATE = 0.15
    ALPHA = 1.2
    BETA = 3.0
    Q = 1.0

    model_count = len(models)
    pheromone = [[1.0] * gpu_num for _ in range(model_count)]

    best_placement = None
    best_kvpr = float('inf')

    for iteration in range(MAX_ITER):
        placements = []
        kvpr_values = []

        for ant in range(NUM_ANTS):
            gpu_loads = [0] * gpu_num
            placement = [[] for _ in range(gpu_num)]
            order = list(range(model_count))
            random.shuffle(order)

            for model_idx in order:
                model = models[model_idx]
                candidates = []
                for gpu in range(gpu_num):
                    if gpu_loads[gpu] + model.model_size <= GPU_MEM_SIZE:
                        temp_models = placement[gpu] + [model]
                        temp_kvpr = kvpr_for_gpu(temp_models)
                        if temp_kvpr == float('inf'):
                            heuristic = 0.0
                        else:
                            heuristic = 1.0 / (temp_kvpr + 1e-6)
                        tau = pheromone[model_idx][gpu]
                        score = (tau ** ALPHA) * (heuristic ** BETA)
                        candidates.append((score, gpu))

                if not candidates:
                    placement = None
                    break

                total = sum(c[0] for c in candidates)
                if total == 0:
                    chosen = random.choice(candidates)[1]
                else:
                    probs = [c[0]/total for c in candidates]
                    chosen = random.choices([c[1] for c in candidates], weights=probs, k=1)[0]

                placement[chosen].append(model)
                gpu_loads[chosen] += model.model_size

            if placement:
                kvpr = max_kvpr({i: placement[i] for i in range(gpu_num)})
                placements.append(placement)
                kvpr_values.append(kvpr)

        if not placements:
            continue

        for i in range(model_count):
            for j in range(gpu_num):
                pheromone[i][j] *= (1 - EVAP_RATE)

        for placement, kvpr in zip(placements, kvpr_values):
            if kvpr == float('inf'):
                continue
            deposit = Q / (kvpr + 0.1)
            for model_idx in range(model_count):
                for gpu in range(gpu_num):
                    if any(m is models[model_idx] for m in placement[gpu]):
                        pheromone[model_idx][gpu] += deposit

        best_idx = min(range(len(kvpr_values)), key=lambda i: kvpr_values[i])
        if kvpr_values[best_idx] < best_kvpr:
            best_kvpr = kvpr_values[best_idx]
            best_placement = {i: placements[best_idx][i] for i in range(gpu_num)}

        if best_kvpr == 0:
            break

    if best_placement is None:
        best_placement = {i: [] for i in range(gpu_num)}
        for i, model in enumerate(models):
            best_placement[i % gpu_num].append(model)

    return best_placement

