def compute_model_placement(gpu_num, models):
    GPU_MEM_SIZE = 80

    def calculate_gpu_kvpr(models_on_gpu):
        if not models_on_gpu:
            return 0.0
        sum_req_rate_slo = sum(m.req_rate / m.slo for m in models_on_gpu)
        sum_model_size = sum(m.model_size for m in models_on_gpu)
        if sum_model_size > GPU_MEM_SIZE:
            return float('inf')
        remaining_mem = GPU_MEM_SIZE - sum_model_size
        if remaining_mem <= 0:
            return float('inf') if sum_req_rate_slo > 0 else 0.0
        return sum_req_rate_slo / remaining_mem

    def calculate_max_kvpr(placement):
        max_kvpr = 0.0
        for gpu_id in range(gpu_num):
            max_kvpr = max(max_kvpr, calculate_gpu_kvpr(placement[gpu_id]))
        return max_kvpr

    def create_initial_solution():
        placement = {i: [] for i in range(gpu_num)}
        mem_used = [0] * gpu_num

        sorted_models = sorted(models, key=lambda m: m.req_rate / m.slo / (m.model_size + 1e-6), reverse=True)

        for model in sorted_models:
            best_gpu = -1
            best_increase = float('inf')

            for gpu_id in range(gpu_num):
                if mem_used[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    old_kvpr = calculate_gpu_kvpr(placement[gpu_id])
                    placement[gpu_id].append(model)
                    new_kvpr = calculate_gpu_kvpr(placement[gpu_id])
                    placement[gpu_id].pop()

                    increase = new_kvpr - old_kvpr
                    if increase < best_increase:
                        best_increase = increase
                        best_gpu = gpu_id

            if best_gpu != -1:
                placement[best_gpu].append(model)
                mem_used[best_gpu] += model.model_size
            else:
                for gpu_id in range(gpu_num):
                    if mem_used[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                        placement[gpu_id].append(model)
                        mem_used[gpu_id] += model.model_size
                        break

        return placement

    def local_search(placement):
        current_kvpr = calculate_max_kvpr(placement)

        for _ in range(1000):
            improved = False

            gpu_kvprs = [calculate_gpu_kvpr(placement[i]) for i in range(gpu_num)]
            max_kvpr = max(gpu_kvprs)
            source_gpus = [i for i, kvpr in enumerate(gpu_kvprs) if kvpr == max_kvpr]

            for src_gpu in source_gpus:
                if not placement[src_gpu]:
                    continue

                for model in placement[src_gpu]:
                    for dst_gpu in range(gpu_num):
                        if dst_gpu == src_gpu:
                            continue

                        src_size = sum(m.model_size for m in placement[src_gpu])
                        dst_size = sum(m.model_size for m in placement[dst_gpu])

                        if dst_size + model.model_size <= GPU_MEM_SIZE:
                            placement[src_gpu].remove(model)
                            placement[dst_gpu].append(model)

                            new_kvpr = calculate_max_kvpr(placement)
                            if new_kvpr < current_kvpr:
                                current_kvpr = new_kvpr
                                improved = True
                                break
                            else:
                                placement[dst_gpu].remove(model)
                                placement[src_gpu].append(model)

                    if improved:
                        break
                if improved:
                    break

            if not improved:
                break

        return placement

    def simulated_annealing(placement):
        current = placement
        current_kvpr = calculate_max_kvpr(current)
        best = {i: list(current[i]) for i in range(gpu_num)}
        best_kvpr = current_kvpr

        temperature = 10.0
        cooling_rate = 0.995
        min_temp = 0.01

        while temperature > min_temp:
            for _ in range(100):
                if len(models) == 0:
                    break

                new_placement = {i: list(current[i]) for i in range(gpu_num)}

                src_gpu = random.randint(0, gpu_num - 1)
                if not new_placement[src_gpu]:
                    continue

                model = random.choice(new_placement[src_gpu])
                dst_gpu = random.randint(0, gpu_num - 1)

                dst_size = sum(m.model_size for m in new_placement[dst_gpu])
                if dst_size + model.model_size > GPU_MEM_SIZE:
                    continue

                new_placement[src_gpu].remove(model)
                new_placement[dst_gpu].append(model)

                new_kvpr = calculate_max_kvpr(new_placement)

                if new_kvpr < current_kvpr or random.random() < math.exp((current_kvpr - new_kvpr) / temperature):
                    current = new_placement
                    current_kvpr = new_kvpr

                    if new_kvpr < best_kvpr:
                        best = {i: list(new_placement[i]) for i in range(gpu_num)}
                        best_kvpr = new_kvpr

            temperature *= cooling_rate

        return best

    best_placement = create_initial_solution()
    best_kvpr = calculate_max_kvpr(best_placement)

    for _ in range(10):
        placement = create_initial_solution()
        placement = local_search(placement)
        placement = simulated_annealing(placement)

        kvpr = calculate_max_kvpr(placement)
        if kvpr < best_kvpr:
            best_kvpr = kvpr
            best_placement = placement

    return best_placement

