    def calculate_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        sum_req_rate_slo = sum(m.req_rate / m.slo for m in gpu_models)
        sum_model_size = sum(m.model_size for m in gpu_models)
        if sum_model_size >= GPU_MEM_SIZE:
            return float('inf')
        return sum_req_rate_slo / (GPU_MEM_SIZE - sum_model_size)

    def create_initial_solution():
        placement = {i: [] for i in range(gpu_num)}
        mem_used = [0] * gpu_num

        sorted_models = sorted(models, key=lambda m: m.req_rate / (m.slo * m.model_size), reverse=True)

        for model in sorted_models:
            best_gpu = -1
            best_kvpr = float('inf')

            for gpu_id in range(gpu_num):
                if mem_used[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    temp_kvpr = calculate_kvpr(placement[gpu_id] + [model])
                    if temp_kvpr < best_kvpr:
                        best_kvpr = temp_kvpr
                        best_gpu = gpu_id

            if best_gpu == -1:
                return {i: [] for i in range(gpu_num)}

            placement[best_gpu].append(model)
            mem_used[best_gpu] += model.model_size

        return placement

    def get_neighbor(placement):
        new_placement = {i: list(models) for i, models in placement.items()}

        gpu_kvprs = [(calculate_kvpr(models), gpu_id) for gpu_id, models in placement.items()]
        max_gpu = max(gpu_kvprs)[1]
        min_gpu = min(gpu_kvprs)[1]

        if not new_placement[max_gpu]:
            return new_placement

        if random.random() < 0.7:
            model_to_move = random.choice(new_placement[max_gpu])
            new_placement[max_gpu].remove(model_to_move)

            possible_targets = [gpu_id for gpu_id in range(gpu_num)
                               if gpu_id != max_gpu and
                               sum(m.model_size for m in new_placement[gpu_id]) + model_to_move.model_size <= GPU_MEM_SIZE]

            if possible_targets:
                target_gpu = random.choice(possible_targets)
                new_placement[target_gpu].append(model_to_move)
            else:
                new_placement[min_gpu].append(model_to_move)
        else:
            if gpu_num < 2:
                return new_placement

            src_gpu, dst_gpu = random.sample(range(gpu_num), 2)
            if not new_placement[src_gpu] or not new_placement[dst_gpu]:
                return new_placement

            model1 = random.choice(new_placement[src_gpu])
            model2 = random.choice(new_placement[dst_gpu])

            if (sum(m.model_size for m in new_placement[src_gpu]) - model1.model_size + model2.model_size <= GPU_MEM_SIZE and
                sum(m.model_size for m in new_placement[dst_gpu]) - model2.model_size + model1.model_size <= GPU_MEM_SIZE):
                new_placement[src_gpu].remove(model1)
                new_placement[dst_gpu].remove(model2)
                new_placement[src_gpu].append(model2)
                new_placement[dst_gpu].append(model1)

        return new_placement

    current_solution = create_initial_solution()
    current_kvpr = max(calculate_kvpr(models) for models in current_solution.values())

    best_solution = {i: list(models) for i, models in current_solution.items()}
    best_kvpr = current_kvpr

    TEMP_INITIAL = 100.0
    TEMP_FINAL = 0.1
    COOLING_RATE = 0.995
    MAX_ITERATIONS = 5000

    temp = TEMP_INITIAL
    iteration = 0

    while temp > TEMP_FINAL and iteration < MAX_ITERATIONS:
        neighbor = get_neighbor(current_solution)
        neighbor_kvpr = max(calculate_kvpr(models) for models in neighbor.values())

        if neighbor_kvpr < current_kvpr or random.random() < math.exp((current_kvpr - neighbor_kvpr) / temp):
            current_solution = neighbor
            current_kvpr = neighbor_kvpr

            if neighbor_kvpr < best_kvpr:
                best_solution = {i: list(models) for i, models in neighbor.items()}
                best_kvpr = neighbor_kvpr

        temp *= COOLING_RATE
        iteration += 1

    if best_kvpr == float('inf'):
        best_solution = {i: [] for i in range(gpu_num)}
        for i, model in enumerate(models):
            best_solution[i % gpu_num].append(model)

    return best_solution

