            return float('inf')
        total_load = sum(m.req_rate / m.slo for m in models_on_gpu)
        remaining = GPU_MEM - total_size
        return total_load / remaining if remaining > 0 else float('inf')

    # Greedy initial placement
    sorted_models = sorted(models, key=lambda m: m.req_rate / m.slo, reverse=True)
