        best_gpu = None
        best_increase = float('inf')

        for gpu in range(gpu_num):
            if mem_used[gpu] + model.model_size <= GPU_MEM:
                new_load = load_used[gpu] + model.req_rate / model.slo
                new_mem = mem_used[gpu] + model.model_size
                new_kvpr = new_load / (GPU_MEM - new_mem) if GPU_MEM > new_mem else float('inf')
                increase = new_kvpr - (load_used[gpu] / (GPU_MEM - mem_used[gpu]) if mem_used[gpu] < GPU_MEM else float('inf'))
                if increase < best_increase:
                    best_increase = increase
                    best_gpu = gpu

        if best_gpu is None:
            # Fallback: place on GPU with most free memory
            best_gpu = max(range(gpu_num), key=lambda g: GPU_MEM - mem_used[g])

        placement[best_gpu].append(model)
        mem_used[best_gpu] += model.model_size
        load_used[best_gpu] += model.req_rate / model.slo

