import collections

def compute_model_placement(gpu_num, models):
    '''
    Args:
        gpu_num: Number of GPUs (int)
        models: List of models with .model_size, .req_rate, .slo

    Returns:
        dict: {gpu_id: [models assigned to that GPU]}
    '''
    GPU_MEM_SIZE = 80

    def calculate_gpu_kvpr(models_on_gpu):
        if not models_on_gpu:
            return 0.0
        sum_req_rate_slo = sum(m.req_rate / m.slo for m in models_on_gpu)
        sum_model_size = sum(m.model_size for m in models_on_gpu)
        if sum_model_size > GPU_MEM_SIZE:
            return float('inf')
        remaining_mem = GPU_MEM_SIZE - sum_model_size
        if remaining_mem <= 0:
            return float('inf') if sum_req_rate_slo > 0 else 0.0
        return sum_req_rate_slo / remaining_mem

    def calculate_max_kvpr(placement):
        max_kvpr = 0.0
        for gpu_id in range(gpu_num):
            max_kvpr = max(max_kvpr, calculate_gpu_kvpr(placement[gpu_id]))
        return max_kvpr

    def create_initial_solution():
        # Greedy approach: sort models by size descending, place on GPU with most available space
        sorted_models = sorted(models, key=lambda m: m.model_size, reverse=True)
        placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        gpu_mem_usage = [0] * gpu_num

        for model in sorted_models:
            # Find GPU with most available space that can fit this model
            best_gpu = None
            max_available = -1

            for gpu_id in range(gpu_num):
                available = GPU_MEM_SIZE - gpu_mem_usage[gpu_id]
                if available >= model.model_size and available > max_available:
                    max_available = available
                    best_gpu = gpu_id

            if best_gpu is not None:
                placement[best_gpu].append(model)
                gpu_mem_usage[best_gpu] += model.model_size
            else:
                # If no GPU can fit the model, place it on any available GPU
                # This should ideally not happen with valid inputs
                for gpu_id in range(gpu_num):
                    if gpu_mem_usage[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                        placement[gpu_id].append(model)
                        gpu_mem_usage[gpu_id] += model.model_size
                        break

        return placement

    def get_neighbor(current_placement):
        # Try to move one model from one GPU to another
        new_placement = {gpu_id: list(current_placement[gpu_id]) for gpu_id in range(gpu_num)}

        # Find a non-empty GPU
        non_empty_gpus = [gpu_id for gpu_id in range(gpu_num) if current_placement[gpu_id]]
        if not non_empty_gpus:
            return new_placement

        src_gpu = random.choice(non_empty_gpus)
        model_to_move = random.choice(new_placement[src_gpu])
        new_placement[src_gpu].remove(model_to_move)

        # Try to find a destination GPU
        dest_gpu = None
        min_kvpr = float('inf')

        # Try different destination GPUs
        for gpu_id in range(gpu_num):
            if gpu_id != src_gpu:
                # Check if we can place the model there
                current_usage = sum(m.model_size for m in new_placement[gpu_id])
                if current_usage + model_to_move.model_size <= GPU_MEM_SIZE:
                    # Add model temporarily and compute KVPR for that GPU
                    temp_placement = {g: list(new_placement[g]) for g in range(gpu_num)}
                    temp_placement[gpu_id].append(model_to_move)
                    kvpr = calculate_gpu_kvpr(temp_placement[gpu_id])

                    if kvpr < min_kvpr:
                        min_kvpr = kvpr
                        dest_gpu = gpu_id

        if dest_gpu is not None:
            new_placement[dest_gpu].append(model_to_move)

        return new_placement

    # Simulated Annealing
    current_solution = create_initial_solution()
    current_kvpr = calculate_max_kvpr(current_solution)
    best_solution = current_solution
    best_kvpr = current_kvpr

    temp = 100.0
    cooling_rate = 0.99
    iterations = 500

    for i in range(iterations):
        new_solution = get_neighbor(current_solution)
        new_kvpr = calculate_max_kvpr(new_solution)

        if new_kvpr < current_kvpr:
            current_solution = new_solution
            current_kvpr = new_kvpr
            if current_kvpr < best_kvpr:
                best_solution = new_solution
                best_kvpr = current_kvpr
        else:
            # Accept worse solution with probability
            if new_kvpr != float('inf') and current_kvpr != float('inf'):
                delta = new_kvpr - current_kvpr
                acceptance_probability = math.exp(-delta / temp)
                if random.random() < acceptance_probability:
                    current_solution = new_solution
                    current_kvpr = new_kvpr
            elif new_kvpr == float('inf') and current_kvpr != float('inf'):
                # Always accept better solution (valid one)
                pass
            elif new_kvpr != float('inf') and current_kvpr == float('inf'):
                # Accept valid solution over invalid one
                current_solution = new_solution
                current_kvpr = new_kvpr
                if current_kvpr < best_kvpr:
                    best_solution = new_solution
                    best_kvpr = current_kvpr

        temp *= cooling_rate
        if best_kvpr == 0:
            break

    # If we couldn't find a good solution, fall back to round-robin
    if best_kvpr == float('inf'):
        final_placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        for i, model in enumerate(models):
            final_placement[i % gpu_num].append(model)
        return final_placement

    return best_solution

