    def kvpr_for_gpu(models_on_gpu):
        if not models_on_gpu:
            return 0.0
        total_size = sum(m.model_size for m in models_on_gpu)
        if total_size >= GPU_MEM_SIZE:
            return float('inf')
        total_weight = sum(m.req_rate / m.slo for m in models_on_gpu)
        return total_weight / (GPU_MEM_SIZE - total_size)

    def evaluate_placement(placement):
        max_kvpr = 0.0
        for gpu_id in range(gpu_num):
            kvpr = kvpr_for_gpu(placement.get(gpu_id, []))
            if kvpr == float('inf'):
                return float('inf')
            max_kvpr = max(max_kvpr, kvpr)
        return max_kvpr

    def initialize_placement():
        placement = {i: [] for i in range(gpu_num)}
        mem_used = [0] * gpu_num

        sorted_models = sorted(models, key=lambda m: m.req_rate / m.slo, reverse=True)

        for model in sorted_models:
            best_gpu = -1
            best_kvpr_increase = float('inf')

            for gpu_id in range(gpu_num):
                if mem_used[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    current_kvpr = kvpr_for_gpu(placement[gpu_id])

                    placement[gpu_id].append(model)
                    new_kvpr = kvpr_for_gpu(placement[gpu_id])
                    placement[gpu_id].pop()

                    kvpr_increase = new_kvpr - current_kvpr
                    if kvpr_increase < best_kvpr_increase:
                        best_kvpr_increase = kvpr_increase
                        best_gpu = gpu_id

            if best_gpu == -1:
                return None

            placement[best_gpu].append(model)
            mem_used[best_gpu] += model.model_size

        return placement

    def get_neighbor(placement):
        new_placement = {i: list(placement[i]) for i in range(gpu_num)}

        if random.random() < 0.8:
            src_gpu = random.randint(0, gpu_num - 1)
            if not new_placement[src_gpu]:
                return new_placement

            model_idx = random.randint(0, len(new_placement[src_gpu]) - 1)
            model = new_placement[src_gpu].pop(model_idx)

            dest_gpu = random.randint(0, gpu_num - 1)
            while dest_gpu == src_gpu:
                dest_gpu = random.randint(0, gpu_num - 1)

            new_placement[dest_gpu].append(model)
        else:
            if gpu_num < 2:
                return new_placement

            gpu1, gpu2 = random.sample(range(gpu_num), 2)
            if not new_placement[gpu1] or not new_placement[gpu2]:
                return new_placement

            idx1 = random.randint(0, len(new_placement[gpu1]) - 1)
            idx2 = random.randint(0, len(new_placement[gpu2]) - 1)

            model1 = new_placement[gpu1][idx1]
            model2 = new_placement[gpu2][idx2]

            new_placement[gpu1][idx1] = model2
            new_placement[gpu2][idx2] = model1

        return new_placement

    def placement_is_valid(placement):
        for gpu_id in range(gpu_num):
            total_size = sum(m.model_size for m in placement[gpu_id])
            if total_size > GPU_MEM_SIZE:
                return False
        return True

    current_placement = initialize_placement()
    if current_placement is None:
        current_placement = {i: [] for i in range(gpu_num)}
        for i, model in enumerate(models):
            current_placement[i % gpu_num].append(model)

    current_score = evaluate_placement(current_placement)
    best_placement = current_placement
    best_score = current_score

    temperature = 10.0
    cooling_rate = 0.995
    iterations = 2000

    for _ in range(iterations):
        neighbor = get_neighbor(current_placement)

        if not placement_is_valid(neighbor):
            continue

        neighbor_score = evaluate_placement(neighbor)

        if neighbor_score < current_score:
            current_placement = neighbor
            current_score = neighbor_score
            if neighbor_score < best_score:
                best_placement = neighbor
                best_score = neighbor_score
        else:
            delta = neighbor_score - current_score
            if delta < 0:
                continue
            if random.random() < math.exp(-delta / temperature):
                current_placement = neighbor
                current_score = neighbor_score

        temperature *= cooling_rate

        if temperature < 0.01:
            break

    if best_score == float('inf'):
        return {i: [] for i in range(gpu_num)}

    return best_placement

